// Analyze toxic backlinks
const links = $input.all().map(i => i.json);

if (links.length === 0) {
  return [{ json: { has_toxic: false, summary: 'No toxic backlinks detected' } }];
}

// Categorize by severity
const critical = links.filter(l => l.spam_score >= 70);  // Very high spam
const warning = links.filter(l => l.spam_score >= 50 && l.spam_score < 70);
const watch = links.filter(l => l.spam_score >= 30 && l.spam_score < 50);

// Mark as toxic in database
const toxicIds = critical.map(l => l.id);

return [{
  json: {
    has_toxic: true,
    total_toxic: links.length,
    critical_count: critical.length,
    warning_count: warning.length,
    watch_count: watch.length,
    critical_links: critical.slice(0, 5),
    warning_links: warning.slice(0, 5),
    toxic_ids: toxicIds
  }
}];

